async function ld(){if(_ok)return;_L=[...D_L];_R=[...D_R];_U=[...D_U];_M=[...D_M];_F=[];try{const[a,b,c,d,e,f]=await Promise.all([window.storage.get("fm3_l"),window.storage.get("fm3_r"),window.storage.get("fm3_u"),window.storage.get("fm3_m"),window.storage.get("fm3_n"),window.storage.get("fm3_f")]);if(a)_L=JSON.parse(a.value);if(b)_R=JSON.parse(b.value);if(c)_U=JSON.parse(c.value);if(d)_M=JSON.parse(d.value);if(e){const n=JSON.parse(e.value);_nL=n.l;_nR=n.r;_nM=n.m;}if(f)_F=JSON.parse(f.value);}catch(e){}; _ok=true;}
async function sv(){try{await Promise.all([window.storage.set("fm3_l",JSON.stringify(_L)),window.storage.set("fm3_r",JSON.stringify(_R)),window.storage.set("fm3_u",JSON.stringify(_U)),window.storage.set("fm3_m",JSON.stringify(_M)),window.storage.set("fm3_n",JSON.stringify({l:_nL,r:_nR,m:_nM})),window.storage.set("fm3_f",JSON.stringify(_F))])}catch(e){}}

// API
const api={
  ls:{all:async(f={})=>{await ld();let r=[..._L];if(f.cat)r=r.filter(l=>l.cat===f.cat);if(f.reg)r=r.filter(l=>l.ct===f.reg);if(f.tx)r=r.filter(l=>l.tx===f.tx);if(f.q){const q=f.q.toLowerCase();r=r.filter(l=>l.tt.toLowerCase().includes(q)||l.ds.toLowerCase().includes(q));}if(f.ft)r=r.filter(l=>l.ft);if(f.minPr!==undefined)r=r.filter(l=>l.pr>=f.minPr);if(f.maxPr!==undefined&&f.maxPr>0)r=r.filter(l=>l.pr<=f.maxPr);if(f.sort==="priceLow")r.sort((a,b)=>a.pr-b.pr);else if(f.sort==="priceHigh")r.sort((a,b)=>b.pr-a.pr);else if(f.sort==="views")r.sort((a,b)=>b.vw-a.vw);else r.sort((a,b)=>b.at.localeCompare(a.at));return r;},get:async id=>{await ld();return _L.find(l=>l.id===id);},feat:async()=>{await ld();return _L.filter(l=>l.ft);},byUser:async u=>{await ld();return _L.filter(l=>l.uid===u);},add:async d=>{await ld();const n={...d,id:`l${_nL++}`,vw:0,at:new Date().toISOString().split("T")[0],ft:false,st:"active"};_L.unshift(n);await sv();return n;},del:async id=>{await ld();_L=_L.filter(l=>l.id!==id);await sv();}},
  us:{get:async id=>{await ld();return _U.find(u=>u.id===id);},all:async()=>{await ld();return[..._U];},upd:async(id,d)=>{await ld();const i=_U.findIndex(u=>u.id===id);if(i>=0){_U[i]={..._U[i],...d};await sv();return _U[i];}},reg:async d=>{await ld();const n={...d,id:`u${Date.now()}`,vf:false,rt:0,rv:0,jn:new Date().toISOString().slice(0,7),role:"user",plan:"free"};_U.push(n);await sv();return n;}},
  rv:{byL:async lid=>{await ld();return _R.filter(r=>r.lid===lid);},add:async d=>{await ld();const n={...d,id:`r${_nR++}`,at:new Date().toISOString().split("T")[0]};_R.push(n);await sv();return n;}},
  msg:{convos:async uid=>{await ld();const ms=_M.filter(m=>m.from===uid||m.to===uid);const mp={};ms.forEach(m=>{const o=m.from===uid?m.to:m.from;const k=[uid,o,m.lid].sort().join("-");if(!mp[k])mp[k]={other:o,lid:m.lid,msgs:[],last:m.at};mp[k].msgs.push(m);if(m.at>mp[k].last)mp[k].last=m.at;});return Object.values(mp).sort((a,b)=>b.last.localeCompare(a.last));},thread:async(uid,o,lid)=>{await ld();return _M.filter(m=>m.lid===lid&&((m.from===uid&&m.to===o)||(m.from===o&&m.to===uid))).sort((a,b)=>new Date(a.at)-new Date(b.at));},send:async d=>{await ld();const n={...d,id:`m${_nM++}`,at:new Date().toISOString()};_M.push(n);await sv();return n;}},
  fav:{get:async uid=>{await ld();return _F.filter(f=>f.uid===uid).map(f=>f.lid);},tog:async(uid,lid)=>{await ld();const i=_F.findIndex(f=>f.uid===uid&&f.lid===lid);if(i>=0)_F.splice(i,1);else _F.push({uid,lid});await sv();return _F.filter(f=>f.uid===uid).map(f=>f.lid);}},
};

// CONTEXT
const Ctx=createContext();
function Prov({children}){
  const[pg,sPg]=useState("browse");const[sL,sSL]=useState(null);const[sU,sSU]=useState(null);const[fl,sFl]=useState({});
  const[mob,sMob]=useState(window.innerWidth<768);const[usr,sUsr]=useState(null);const[auth,sAuth]=useState(false);
  const[toast,sToast]=useState(null);const[dv,sDv]=useState(0);const[cTo,sCTo]=useState(null);const[cLid,sCLid]=useState(null);
  const[lang,sLang]=useState("en");const[notifs,sNotifs]=useState({area:true,msg:true,price:false});
  const[favs,sFavs]=useState([]);
  useEffect(()=>{const h=()=>sMob(window.innerWidth<768);window.addEventListener("resize",h);return()=>window.removeEventListener("resize",h);},[]);
  useEffect(()=>{(async()=>{try{const s=await window.storage.get("fm3_s");if(s){const u=JSON.parse(s.value);sUsr(u);const f=await api.fav.get(u.id);sFavs(f);}const lg=await window.storage.get("fm3_lang");if(lg)sLang(lg.value);}catch(e){}})();},[]);
  const t=useCallback(k=>T[lang]?.[k]||T.en[k]||k,[lang]);
  const dir=lang==="ar"?"rtl":"ltr";
  const nav=useCallback((p,d)=>{if(d?.lid)sSL(d.lid);if(d?.uid)sSU(d.uid);if(d?.fl)sFl(d.fl);if(d?.cTo)sCTo(d.cTo);if(d?.cLid)sCLid(d.cLid);sPg(p);window.scrollTo(0,0);},[]);
  const login=useCallback(async u=>{sUsr(u);try{await window.storage.set("fm3_s",JSON.stringify(u));}catch(e){};api.fav.get(u.id).then(sFavs);},[]);
  const logout=useCallback(async()=>{sUsr(null);sFavs([]);try{await window.storage.delete("fm3_s");}catch(e){}sPg("home");},[]);
  const nfy=useCallback((m,tp="ok")=>{sToast({m,tp});setTimeout(()=>sToast(null),3000);},[]);
  const rfr=useCallback(()=>sDv(v=>v+1),[]);
  const rqA=useCallback(()=>{if(!usr){sAuth(true);return false;}return true;},[usr]);
  const setLang=useCallback(async l=>{sLang(l);try{await window.storage.set("fm3_lang",l);}catch(e){}},[]);
  const togFav=useCallback((lid)=>{if(!usr)return;api.fav.tog(usr.id,lid).then(sFavs);},[usr]);
  return <Ctx.Provider value={{pg,nav,sL,sU,fl,sFl,mob,usr,login,logout,auth,sAuth,toast,nfy,dv,rfr,rqA,cTo,cLid,t,lang,setLang,dir,notifs,favs,togFav}}>{children}</Ctx.Provider>;
}
const useA=()=>useContext(Ctx);

